  for(const [lang,values] of Object.entries(EXTRA_REPORT_VEHICLE_FILTER)) Object.assign(T[lang] ||= {},values);
  const english = new Set(Object.keys(T.nl));
  const nodeKeys = new WeakMap();
  const attrKeys = new WeakMap();
  let current = 'en';
  function normalize(lang){ if(!lang)return 'en'; const exact=supported.find(x=>x.toLowerCase()===lang.toLowerCase()); if(exact)return exact; const base=lang.split('-')[0]; return supported.includes(base)?base:'en'; }
  function tr(text, lang=current){ return lang==='en' ? text : (T[lang]?.[text] ?? T[lang.split('-')[0]]?.[text] ?? text); }
